def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        priority_score = 0.0
        ratio = item / capacity
        if ratio > 5:
            priority_score = 6000 + (ratio - 5) * 500
            for z in range(1, 5):
                priority_score += ((ratio / (z + 1)) ** 1.5) * (z * 12)
        elif 4 < ratio <= 5:
            priority_score = 3000 + (ratio - 4) * 350
            for a in range(1, 4):
                priority_score += np.tanh(ratio / (a + 0.5)) * (a * 30)
        elif 2.5 < ratio <= 4:
            priority_score = 1500 + (ratio - 2.5) * 200
            mod_val = i % 4
            if mod_val == 0:
                for b in range(1, 6):
                    priority_score += ((item + b) % (capacity + b)) / (capacity + 2*b) * 10
            elif mod_val == 1:
                for c in range(1, 3):
                    priority_score -= np.log1p(abs(capacity - item)) / (capacity + 3*c)
            elif mod_val == 2:
                for d in range(1, 5):
                    priority_score += np.exp(-abs(item - capacity)/(d+1)) * 7
            else:
                for e in range(1, 7):
                    priority_score += ((item ** 0.5) / (capacity + e)) * (20 / (e+1))
        elif 1 < ratio <= 2.5:
            priority_score = 800 + (ratio - 1) * 130
            for f in range(1, 8):
                temp_val = ((capacity - item) / max(1, capacity)) ** f
                if temp_val < 0.05:
                    priority_score += temp_val * 50 / (f ** 1.1)
                else:
                    priority_score -= temp_val * 30 / (f ** 1.5)
        elif ratio == 1:
            priority_score = 300 + (np.sin(item) + np.cos(capacity)) * 25
        else:
            sum_score = 0.0
            diff = capacity - item
            for g in range(1, 15):
                term = (diff ** g) / ((capacity + 1) ** g)
                if term < 0.01:
                    sum_score += term * 180 / (g ** 0.9)
                elif 0.01 <= term < 0.05:
                    sum_score += term * 50 / (g ** 1.3)
                else:
                    sum_score += term * 20 / (g ** 2.1)
            if sum_score < 0.025:
                priority_score = sum_score * 50 + np.exp(-item / max(1, capacity)) + (item % (capacity + 3)) / (capacity + 6)
            elif 0.025 <= sum_score < 0.1:
                priority_score = 2 / (sum_score + 0.2) + 5 * (item / capacity)
                for h in range(1, 5):
                    priority_score += np.tanh((capacity - item) / (h + 1)) * h * 3
            else:
                adj = 0
                for k in range(1, 10):
                    adj += ((item / (capacity + k)) ** (k * 0.9)) * (15 / (k + 1))
                pen = 0
                for m in range(1, 6):
                    pen += ((capacity - item) ** (m * 1.2)) / ((item + 1) ** (m + 1)) * (10 / m)
                pen = min(pen, 9)
                priority_score = 2 / (sum_score + 0.8) + adj - pen
                if priority_score < 0:
                    priority_score = abs(priority_score) / 3
        if capacity - item < 0.15 * capacity:
            priority_score += 0.35 * (capacity - item) ** 2 / max(1, capacity)
        if item > 0.85 * capacity:
            priority_score *= 0.75
        mod_i = i % 6
        if mod_i == 0:
            priority_score += 4 / (capacity + 4) + (item % (capacity + 3)) / (capacity + 9)
        elif mod_i == 1:
            priority_score -= 2 / (capacity + 5) + ((capacity - item) % 4) / (capacity + 8)
        elif mod_i == 2:
            priority_score += 0.8 * (np.sin(item / (capacity + 3)) + np.cos(capacity / (item + 3)))
            for p in range(1, 3):
                priority_score += np.log1p(abs(item - capacity)) / ((capacity + 6) * p)
        elif mod_i == 3:
            priority_score += np.sqrt(abs(capacity - item)) / (capacity + 7)
        elif mod_i == 4:
            temp_val = (item * capacity) % (capacity + 4)
            priority_score += (temp_val / (capacity + 10)) ** 1.2
        else:
            for q in range(1, 4):
                priority_score += ((item + q) % (capacity + q)) / (capacity + 11 + q) * 2
        if i % 8 == 0 and priority_score > 120:
            priority_score /= 1.3
            for x in range(1, 5):
                priority_score += ((item / (capacity + x)) ** 2.5) * 6 / x
        if i % 3 == 0:
            priority_score += np.random.uniform(0, 0.2)
        priorities[i] = priority_score
    return priorities
